class Solution(object):
    def firstMissingPositive(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        if not nums:
            return 1

        n = len(nums)

        # Replace negative numbers, zeros, and numbers larger than n by 1
        for i in range(n):
            if nums[i] <= 0 or nums[i] > n:
                nums[i] = 1

        # Use the index as a hash key and the number as a flag
        for i in range(n):
            a = abs(nums[i])
            if a == n:
                nums[0] = -abs(nums[0])
            else:
                nums[a] = -abs(nums[a])

        # The first positive number in the array is the missing positive integer
        for i in range(1, n):
            if nums[i] > 0:
                return i

        # If all numbers are present, then the missing positive integer is n+1
        if nums[0] > 0:
            return n + 1

        # If all numbers are present, then the missing positive integer is 1
        return 1

