    def searchRange(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: List[int]
        """
        def binary_search(nums, target, find_left):
            left, right = 0, len(nums) - 1
            while left <= right:
                mid = (left + right) // 2
                if nums[mid] < target:
                    left = mid + 1
                elif nums[mid] > target:
                    right = mid - 1
                else:
                    if find_left:
                        if mid == 0 or nums[mid - 1] != target:
                            return mid
                        right = mid - 1
                    else:
                        if mid == len(nums) - 1 or nums[mid + 1] != target:
                            return mid
                        left = mid + 1
            return -1

        return [binary_search(nums, target, True), binary_search(nums, target, False)]

