        if valueDiff < 0 or indexDiff < 0:
            return False

        bucket = {}
        width = valueDiff + 1

        for i, num in enumerate(nums):
            bucket_num = num // width
            if bucket_num in bucket:
                return True
            if bucket_num - 1 in bucket and abs(num - bucket[bucket_num - 1]) < width:
                return True
            if bucket_num + 1 in bucket and abs(num - bucket[bucket_num + 1]) < width:
                return True

