class Solution(object):
    def countNodes(self, root):
        """
        :type root: TreeNode
        :rtype: int
        """
        if root is None:
            return 0

        left_height = 0
        right_height = 0

        # Calculate the height of the left subtree
        node = root
        while node:
            left_height += 1
            node = node.left

        # Calculate the height of the right subtree
        node = root
        while node:
            right_height += 1
            node = node.right

        # If the left and right heights are equal, it means the tree is a perfect binary tree
        if left_height == right_height:
            return 2**left_height - 1

        # Otherwise, recursively calculate the number of nodes in the left and right subtrees
        else:
            return 1 + self.countNodes(root.left) + self.countNodes(root.right)

