        :type s: str
        :rtype: bool
        """
        stack = []
        brackets = {
            ')': '(',
            ']': '[',
            '}': '{'
        }

        for char in s:
            if char in brackets.values():  # open bracket
                stack.append(char)
            elif char in brackets.keys():  # close bracket
                if stack and brackets[char] == stack[-1]:
                    stack.pop()
                else:
                    return False
            else:
                return False

