import heapq

class Solution(object):
    def cutOffTree(self, forest):
        if not forest:
            return -1
        m, n = len(forest), len(forest[0])
        trees = []
        for i in range(m):
            for j in range(n):
                if forest[i][j] > 1:
                    trees.append((forest[i][j], i, j))
        trees.sort()
        dirs = [(0,1),(0,-1),(1,0),(-1,0)]
        steps = 0
        start = (0,0)
        for tree in trees:
            dist = self.bfs(forest, start, tree[1:], dirs)
            if dist < 0: 
                return -1
            steps += dist
            start = tree[1:]
        return steps

    def bfs(self, forest, start, target, dirs):
        m, n = len(forest), len(forest[0])
        queue = [(0, start)]
        visited = set([start])
        while queue:
            dist, point = heapq.heappop(queue)
            if point == target:
                return dist
            for dir in dirs:
                x, y = point[0] + dir[0], point[1] + dir[1]
                if 0 <= x < m and 0 <= y < n and forest[x][y] != 0 and (x, y) not in visited:
                    visited.add((x, y))
                    heapq.heappush(queue, (dist + 1, (x, y)))
        return -1

