import collections

class Solution(object):
    def containVirus(self, isInfected):
        self.d = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        self.walls_used = 0
        self.isInfected = isInfected
        self.m, self.n = len(isInfected), len(isInfected[0])
        self.visited = [[0]*self.n for _ in range(self.m)]
        self.frontiers = []
        self.dfs_components = []
        self.pq = []
        while True:
            self.dfs_components = []
            self.frontiers = []
            for i in range(self.m):
                for j in range(self.n):
                    if self.isInfected[i][j] == 1 and self.visited[i][j] == 0:
                        self.frontiers.append((i, j))
                        self.dfs_components.append(self.dfs(i, j))
            if not self.dfs_components:
                break
            self.pq.append((-len(self.dfs_components[0]), self.dfs_components[0]))
            self.dfs_components[0] = -1
        while self.pq:
            _, component = heapq.heappop(self.pq)
            if component != -1:
                self.build_walls(component)
        return self.walls_used

    def dfs(self, i, j):
        self.visited[i][j] = 1
        component = []
        frontier = []
        for di, dj in self.d:
            ni, nj = i + di, j + dj
            if 0 <= ni < self.m and 0 <= nj < self.n:
                if self.isInfected[ni][nj] == 1 and self.visited[ni][nj] == 0:
                    frontier.append((ni, nj))
                    component.extend(self.dfs(ni, nj))
                elif self.isInfected[ni][nj] == 0:
                    frontier.append((ni, nj))
        if frontier:
            self.frontiers.extend(frontier)
        return component

    def build_walls(self, component):
        for i, j in self.frontiers:
            self.isInfected[i][j] = -1
        self.walls_used += len(self.frontiers)
        for i, j in component:
            self.isInfected[i][j] = 1

