            return 0

        memo = {}
        max_len = 0
        directions = [(0, 1), (1, 0), (-1, 0), (0, -1)]
        rows, cols = len(matrix), len(matrix[0])

        def dfs(i, j):
            if (i, j) in memo:
                return memo[(i, j)]

            longest = 0
            for direction in directions:
                x, y = i + direction[0], j + direction[1]
                if 0 <= x < rows and 0 <= y < cols and matrix[x][y] > matrix[i][j]:
