        :type n: int
        :rtype: int
        """
        if n <= 0:
            return 0

        # Create an array to store the counts
        counts = [0] * (n + 1)
        counts[0] = 0

        # Initialize the count for 1 digit numbers
        for i in range(1, 10):
            counts[i] = 1

        # Calculate counts for 2 digit numbers, 3 digit numbers, ..., up to n digit numbers
        for digits in range(2, len(str(n)) + 1):
            # Calculate the number of 1s in the current digit range
            counts[digits] = counts[digits - 1] * 10 + pow(10, digits - 1)

