import heapq

class Solution(object):
    def medianSlidingWindow(self, nums, k):
        if not nums or k == 0:
            return []

        # Create max heap and min heap
        max_heap, min_heap = [], []
        result = []
        for i in range(len(nums)):
            # Add new number to max heap
            heapq.heappush(max_heap, -nums[i])

            # Maintain heap property by moving largest number to min heap
            if len(max_heap) > len(min_heap) + 1:
                heapq.heappush(min_heap, -heapq.heappop(max_heap))

            # Maintain heap property by moving smallest number to max heap
            if min_heap and max_heap[0] > min_heap[0]:
                heapq.heappush(max_heap, -heapq.heappop(min_heap))
                heapq.heappush(min_heap, -heapq.heappop(max_heap))

            # Calculate median
            if i >= k - 1:
                if k % 2 == 0:
                    result.append((min_heap[0] - max_heap[0]) / 2.0)
                else:
                    result.append(-max_heap[0])

                # Remove number from window
                num_to_remove = nums[i - k + 1]
                if num_to_remove <= -max_heap[0]:
                    max_heap.remove(-num_to_remove)
                    heapq.heapify(max_heap)
                else:
                    min_heap.remove(num_to_remove)
                    heapq.heapify(min_heap)

        return result

