class Solution(object):
    def findRedundantDirectedConnection(self, edges):
        """
        :type edges: List[List[int]]
        :rtype: List[int]
        """
        n = len(edges)
        parent, roots, ranks = list(range(n+1)), [0] * (n+1), [0] * (n+1)
        first, second = None, None
        for i, edge in enumerate(edges):
            if parent[edge[1]] == 0:
                parent[edge[1]] = edge[0]
            else:
                first = [parent[edge[1]], edge[1]]
                second = [edge[0], edge[1]]
                edges[i][1] = 0
        for edge in edges:
            if edge[1] == 0:
                continue
            u, v = edge[0], edge[1]
            if self.union(roots, ranks, u, v) == False:
                if first is None:
                    return edge
                return first
        return second

    def union(self, roots, ranks, u, v):
        rootU = self.find(roots, u)
        rootV = self.find(roots, v)
        if rootU != rootV:
            if ranks[rootU] > ranks[rootV]:
                roots[rootV] = rootU
            else:
                roots[rootU] = rootV
                if ranks[rootU] == ranks[rootV]:
                    ranks[rootV] += 1
            return True
        return False

    def find(self, roots, node):
        if roots[node] != node:
            roots[node] = self.find(roots, roots[node])
        return roots[node]

