class Solution(object):
    def cherryPickup(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        n = len(grid)
        dp = [[[[-1]*n for _ in range(n)] for _ in range(n)] for _ in range(n)]

        def dfs(x1, y1, x2, y2):
            if x1 >= n or y1 >= n or x2 >= n or y2 >= n or grid[x1][y1] == -1 or grid[x2][y2] == -1:
                return -1
            if dp[x1][y1][x2][y2] != -1:
                return dp[x1][y1][x2][y2]
            if x1 == n-1 and y1 == n-1:
                return grid[x1][y1]
            cherries = grid[x1][y1] if (x1, y1) != (x2, y2) else grid[x1][y1]
            right = dfs(x1, y1+1, x2, y2+1)
            down = dfs(x1+1, y1, x2+1, y2)
            max_cherries = max(right, down)
            if max_cherries != -1:
                cherries += max_cherries
            dp[x1][y1][x2][y2] = cherries
            return cherries

        return max(0, dfs(0, 0, 0, 0))

