class Solution(object):
    def splitArray(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        left, right = max(nums), sum(nums)
        while left < right:
            mid = (left + right) // 2
            if self.check(nums, mid, k):
                right = mid
            else:
                left = mid + 1
        return left

    def check(self, nums, mid, k):
        cnt = 0
        for num in nums:
            if cnt + num > mid:
                cnt = num
                k -= 1
                if k < 0:
                    return False
            else:
                cnt += num
        return True

