class Solution(object):
    def canCross(self, stones):
        """
        :type stones: List[int]
        :rtype: bool
        """
        stone_positions = set(stones)
        dp = {}

        def dfs(stone, jump):
            if stone == stones[-1]:
                return True
            if stone not in stone_positions or jump <= 0:
                return False
            if (stone, jump) in dp:
                return dp[(stone, jump)]

            dp[(stone, jump)] = dfs(stone + jump, jump) or dfs(stone + jump, jump - 1) or dfs(stone + jump, jump + 1)
            return dp[(stone, jump)]

        return dfs(0, 1)

