from collections import Counter

class Solution(object):
    def findSubstring(self, s, words):
        if not s or not words:
            return []

        word_len, num_words = len(words[0]), len(words)
        word_counter = Counter(words)

        results = []
        for i in range(len(s) - word_len * num_words + 1):
            seen = Counter()
            for j in range(i, i + word_len * num_words, word_len):
                word = s[j: j + word_len]
                if word in word_counter:
                    seen[word] += 1
                    if seen[word] > word_counter[word]:
                        break
                else:
                    break
            if seen == word_counter:
                results.append(i)

        return results

