        max_of_left[0] = arr[0]
        for i in range(1, len(arr)):
            max_of_left[i] = max(max_of_left[i-1], arr[i])

        min_of_right = [0] * len(arr)
        min_of_right[-1] = arr[-1]
        for i in range(len(arr)-2, -1, -1):
            min_of_right[i] = min(min_of_right[i+1], arr[i])

