import collections
class Solution(object):
    def minStickers(self, stickers, target):
        """
        :type stickers: List[str]
        :type target: str
        :rtype: int
        """
        def update(c, t):
            for i in range(len(t)):
                if t[i] == c:
                    t[i] = '0'
                    return True
            return False

        def check(t, s):
            for c in s:
                if c not in t:
                    return False
                if not update(c, t):
                    return False
            return True

        dp = [0] + [-1] * len(target)
        for i in range(len(target)):
            if dp[i] != -1:
                for s in stickers:
                    t = list(target[i:])
                    if check(t, s):
                        for j in range(len(t)):
                            if dp[i + j + 1] == -1 or dp[i + j + 1] > dp[i] + 1:
                                dp[i + j + 1] = dp[i] + 1
        return dp[-1]

