class Solution(object):
    def search(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: bool
        """
        if not nums:
            return False

        # Find the pivot point
        pivot = self.findPivot(nums, 0, len(nums) - 1)

        # Perform binary search on the appropriate part of the array
        if nums[pivot] == target:
            return True
        if nums[0] <= target:
            return self.binarySearch(nums, 0, pivot, target)
        return self.binarySearch(nums, pivot + 1, len(nums) - 1, target)

    def findPivot(self, nums, low, high):
        # Base cases
        if high < low:
            return 0
        if high == low:
            return low

        mid = (low + high) // 2

        if mid < high and nums[mid] > nums[mid + 1]:
            return mid
        if mid > low and nums[mid] < nums[mid - 1]:
            return mid - 1
        if nums[low] >= nums[mid]:
            return self.findPivot(nums, low, mid - 1)
        return self.findPivot(nums, mid + 1, high)

    def binarySearch(self, nums, low, high, target):
        if high < low:
            return False

        mid = (low + high) // 2

        if nums[mid] == target:
            return True
        if nums[mid] > target:
            return self.binarySearch(nums, low, mid - 1, target)
        return self.binarySearch(nums, mid + 1, high, target)

