class Solution(object):
    def solveSudoku(self, board):
        """
        :type board: List[List[str]]
        :rtype: None Do not return anything, modify board in-place instead.
        """
        def is_valid(board, row, col, num):
            # Check if 'num' is not already placed in current row,
            # current column and current 3x3 box
            for x in range(9):
                if board[row][x] == num or board[x][col] == num:
                    return False
            start_row, start_col = row - row % 3, col - col % 3
            for i in range(3):
                for j in range(3):
                    if board[i + start_row][j + start_col] == num:
                        return False
            return True

        def solve(board):
            for i in range(9):
                for j in range(9):
                    if board[i][j] == ".":
                        for num in "123456789":
                            if is_valid(board, i, j, num):
                                board[i][j] = num  # Try this number for this cell
                                if solve(board):  # Recursive call
                                    return True  # If we get a solution, return True
                                else:
                                    board[i][j] = "."  # Otherwise, undo (backtrack)
                        return False  # If no number can be placed in this cell, return False
            return True  # If we have reached here, we have a solution

        solve(board)

