class Solution(object):
    def candy(self, ratings):
        """
        :type ratings: List[int]
        :rtype: int
        """
        n = len(ratings)
        left = [1]*n
        right = [1]*n

        # Traverse from left to right and fill in the left array
        for i in range(1, n):
            if ratings[i] > ratings[i-1]:
                left[i] = left[i-1] + 1

        # Traverse from right to left and fill in the right array
        for i in range(n-2, -1, -1):
            if ratings[i] > ratings[i+1]:
                right[i] = right[i+1] + 1

        # The total number of candies is the maximum of the left and right arrays
        return sum(max(left[i], right[i]) for i in range(n))

