        :type pattern: str
        :type s: str
        :rtype: bool
        """
        map_char = {}
        map_word = {}

        words = s.split(' ')

        if len(words) != len(pattern):
            return False

        for p, w in zip(pattern, words):
            if p not in map_char:
                if w in map_word:
                    return False
                else:
