    def solveNQueens(self, n):
        """
        :type n: int
        :rtype: List[List[str]]
        """
        res = []
        queens = [-1] * n
        self.dfs(queens, 0, res)
        return res

    def dfs(self, queens, row, res):
        n = len(queens)
        if row == n:
            res.append(self.draw_board(queens))
            return
        for col in range(n):
            if self.is_valid(queens, row, col):
                queens[row] = col
                self.dfs(queens, row + 1, res)

    def is_valid(self, queens, row, col):
        for i in range(row):
            if queens[i] == col or queens[i] - i == col - row or queens[i] + i == col + row:
                return False
        return True

    def draw_board(self, queens):
        n = len(queens)
        board = []
        for i in range(n):
            row = ['Q' if j == queens[i] else '.' for j in range(n)]
            board.append(''.join(row))
        return board

