import heapq

class Solution(object):
    def thirdMax(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        nums = list(set(nums))
        if len(nums) < 3:
            return max(nums)
        heap = []
        for num in nums:
            heapq.heappush(heap, num)
            if len(heap) > 3:
                heapq.heappop(heap)
        return heapq.heappop(heap)
